// // This module implements a 16-bit DRAM cell with a 16-bit data input, a write enable signal, and a clock signal. Data is stored on the falling edge of the clock when the write enable is high.
module dram_cell (
    input wire [7:0] data_in,
    input wire write_enable,
    input wire clk,
    output reg [7:0] data_out
);
    always @(posedge clk) begin
        if (write_enable) begin
            data_out <= data_in;
        end
    end
endmodule
